import{_ as t,o as d,c as a,ae as o}from"./chunks/framework.DTwQaIIa.js";const u=JSON.parse('{"title":"Commands and Permissions","description":"","frontmatter":{},"headers":[],"relativePath":"en/modules/attribute/commands.md","filePath":"en/modules/attribute/commands.md"}'),s={name:"en/modules/attribute/commands.md"};function i(n,e,r,c,l,p){return d(),a("div",null,[...e[0]||(e[0]=[o(`<h1 id="commands-and-permissions" tabindex="-1">Commands and Permissions <a class="header-anchor" href="#commands-and-permissions" aria-label="Permalink to &quot;Commands and Permissions&quot;">​</a></h1><h2 id="commands" tabindex="-1">Commands <a class="header-anchor" href="#commands" aria-label="Permalink to &quot;Commands&quot;">​</a></h2><p>Root command: <code>/emakiattribute</code> (aliases <code>/eattribute</code>, <code>/ea</code>)</p><table tabindex="0"><thead><tr><th>Subcommand</th><th>Usage</th><th>Permission</th><th>Description</th></tr></thead><tbody><tr><td><code>help</code></td><td><code>/ea help</code></td><td><code>emakiattribute.use</code></td><td>Display help information</td></tr><tr><td><code>reload</code></td><td><code>/ea reload</code></td><td><code>emakiattribute.reload</code></td><td>Asynchronously reload all config files, outputs load statistics on completion</td></tr><tr><td><code>resync</code></td><td><code>/ea resync [player|all]</code></td><td><code>emakiattribute.resync</code></td><td>Re-sync attribute snapshots. No argument syncs yourself, <code>all</code> syncs all online players</td></tr><tr><td><code>preview</code></td><td><code>/ea preview [player] [slot]</code></td><td><code>emakiattribute.debug</code></td><td>Preview the attribute snapshot of a specified player&#39;s item in a given slot</td></tr><tr><td><code>dump</code></td><td><code>/ea dump [player]</code></td><td><code>emakiattribute.debug</code></td><td>Export a player&#39;s full combat attribute snapshot and resource state</td></tr><tr><td><code>debug</code></td><td><code>/ea debug [player] [toggle|on|off]</code></td><td><code>emakiattribute.debug</code></td><td>Toggle combat debug mode; when enabled, outputs detailed damage calculation logs to console</td></tr><tr><td><code>lint</code></td><td><code>/ea lint</code></td><td><code>emakiattribute.reload</code></td><td>Check all config files for validity and report potential issues</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">reload Command</p><p><code>reload</code> executes asynchronously and outputs progress messages during the reload process. On completion, it displays the number of loaded attributes, damage types, and profiles.</p></div><h2 id="permission-nodes" tabindex="-1">Permission Nodes <a class="header-anchor" href="#permission-nodes" aria-label="Permalink to &quot;Permission Nodes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Permission</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>emakiattribute.use</code></td><td><code>true</code></td><td>Use basic commands (help)</td></tr><tr><td><code>emakiattribute.reload</code></td><td><code>op</code></td><td>Reload configuration and run lint checks</td></tr><tr><td><code>emakiattribute.resync</code></td><td><code>op</code></td><td>Re-sync attributes</td></tr><tr><td><code>emakiattribute.debug</code></td><td><code>op</code></td><td>Use preview, dump, debug commands</td></tr><tr><td><code>emakiattribute.admin</code></td><td><code>op</code></td><td>Admin permission, includes all above permissions</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Permission Inheritance</p><p><code>emakiattribute.admin</code> is a super permission. Players with this permission can execute all commands without needing individual permission nodes.</p></div><h2 id="preview-slot-names" tabindex="-1">Preview Slot Names <a class="header-anchor" href="#preview-slot-names" aria-label="Permalink to &quot;Preview Slot Names&quot;">​</a></h2><p>The <code>preview</code> command supports the following slot names:</p><table tabindex="0"><thead><tr><th>Slot</th><th>Aliases</th><th>Description</th></tr></thead><tbody><tr><td><code>main_hand</code></td><td><code>mainhand</code>, <code>hand</code></td><td>Main hand</td></tr><tr><td><code>off_hand</code></td><td><code>offhand</code></td><td>Off hand</td></tr><tr><td><code>helmet</code></td><td>—</td><td>Helmet</td></tr><tr><td><code>chestplate</code></td><td><code>chest</code></td><td>Chestplate</td></tr><tr><td><code>leggings</code></td><td><code>legs</code></td><td>Leggings</td></tr><tr><td><code>boots</code></td><td>—</td><td>Boots</td></tr></tbody></table><p>Usage examples:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/ea preview                    # Preview your own main hand item</span></span>
<span class="line"><span>/ea preview main_hand          # Preview your own main hand item</span></span>
<span class="line"><span>/ea preview Steve helmet       # Preview Steve&#39;s helmet</span></span>
<span class="line"><span>/ea preview chestplate         # Preview your own chestplate</span></span></code></pre></div><h2 id="debug-toggle-options" tabindex="-1">Debug Toggle Options <a class="header-anchor" href="#debug-toggle-options" aria-label="Permalink to &quot;Debug Toggle Options&quot;">​</a></h2><p>The <code>debug</code> command supports the following operations:</p><table tabindex="0"><thead><tr><th>Operation</th><th>Aliases</th><th>Description</th></tr></thead><tbody><tr><td><code>toggle</code></td><td>—</td><td>Toggle debug state (default operation)</td></tr><tr><td><code>on</code></td><td><code>enable</code>, <code>true</code></td><td>Enable debug</td></tr><tr><td><code>off</code></td><td><code>disable</code>, <code>false</code></td><td>Disable debug</td></tr></tbody></table><p>Usage examples:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/ea debug                      # Toggle your own debug state</span></span>
<span class="line"><span>/ea debug on                   # Enable your own debug</span></span>
<span class="line"><span>/ea debug Steve off            # Disable Steve&#39;s debug</span></span>
<span class="line"><span>/ea debug Steve                # Toggle Steve&#39;s debug state</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">Debug Mode Performance</p><p>Debug mode outputs a complete log for every damage calculation to the console, including attacker/target snapshots, stage calculation values, crit determination, etc. This may produce a large volume of log output in high-frequency combat scenarios. It is recommended to enable it only when troubleshooting issues.</p></div><h2 id="lint-check-items" tabindex="-1">Lint Check Items <a class="header-anchor" href="#lint-check-items" aria-label="Permalink to &quot;Lint Check Items&quot;">​</a></h2><p>The <code>lint</code> command checks the following configuration areas:</p><table tabindex="0"><thead><tr><th>Check Area</th><th>Description</th></tr></thead><tbody><tr><td>Configuration</td><td>Whether <code>default_damage_type</code> points to a valid damage type; whether damage type references in <code>allowed_damage_causes</code> are valid</td></tr><tr><td>Attribute Definitions</td><td>Format and field validity of attribute files</td></tr><tr><td>Damage Types</td><td>Format and stage definition validity of damage type files</td></tr><tr><td>Default Attribute Config</td><td>Format validity of profile files</td></tr><tr><td>Lore Formats</td><td>Format validity of Lore format files</td></tr><tr><td>Attribute Presets</td><td>Format validity of preset files</td></tr><tr><td>Attribute Read Conditions</td><td>Format and reference validity of condition files</td></tr></tbody></table>`,22)])])}const h=t(s,[["render",i]]);export{u as __pageData,h as default};
